3	async function getFixtureIds(
4		request: import('@playwright/test').APIRequestContext
5	): Promise<{ nodeId: string; projectId: string }> {
6		const nodeResp = await request.post('/graphql', {
7			data: { query: '{ nodeInfo { id name } }' }
8		});
9		const nodeBody = (await nodeResp.json()) as {
10			data: { nodeInfo: { id: string; name: string } };
11		};
12		const projectsResp = await request.get('/api/projects');
13		const projects = (await projectsResp.json()) as Array<{
14			id: string;
15			name: string;
16			path: string;
17		}>;
18		const fixture = projects.find((p) => /(^|\/)ddx-e2e-/.test(p.path) || /^ddx-e2e-/.test(p.name));
19		if (!fixture) {
20			throw new Error(
21				`fixture server has no ddx-e2e-* project registered (got: ${projects
22					.map((p) => p.id)
23					.join(', ')})`
24			);
25		}
26		return {
27			nodeId: nodeBody.data.nodeInfo.id,
28			projectId: fixture.id
29		};
30	}
