32	async function readFirstPaint(page: import('@playwright/test').Page): Promise<number> {
33		return page.evaluate(() => {
34			const entry = performance
35				.getEntriesByType('paint')
36				.find((item) => item.name === 'first-paint') as PerformanceEntry | undefined;
37			return entry ? Math.round(entry.startTime) : -1;
38		});
39	}
