41	async function measureScrollSmoothness(page: import('@playwright/test').Page): Promise<{
42		averageFrameMs: number;
43		framesPerSecond: number;
44		samples: number;
45	}> {
46		return page.evaluate(async () => {
47			const scrollRoot = document.scrollingElement ?? document.documentElement;
48			const intervals: number[] = [];
49			let previous = performance.now();
50			const start = previous;
51			const durationMs = 1200;
52	
53			while (performance.now() - start < durationMs) {
54				window.scrollBy(0, 900);
55				await new Promise<void>((resolve) => requestAnimationFrame(() => resolve()));
56				const now = performance.now();
57				intervals.push(now - previous);
58				previous = now;
59			}
60	
61			scrollRoot.scrollTop = 0;
62			window.scrollTo(0, 0);
63			const averageFrameMs = intervals.reduce((sum, value) => sum + value, 0) / intervals.length;
64			return {
65				averageFrameMs: Number(averageFrameMs.toFixed(1)),
66				framesPerSecond: Number((1000 / averageFrameMs).toFixed(1)),
67				samples: intervals.length
68			};
69		});
70	}
