72	test('2k fixture loads without crash', async ({ page, request }) => {
73		test.setTimeout(150_000);
74		const ids = await getFixtureIds(request);
75		const base = `/nodes/${ids.nodeId}/projects/${ids.projectId}/artifacts?mediaType=text%2Fmarkdown`;
76	
77		await page.goto(base, { waitUntil: 'domcontentloaded', timeout: 60_000 });
78		await expect(page.getByRole('heading', { name: 'Artifacts' })).toBeVisible({ timeout: 60_000 });
79		await expect(page.getByText(/2000 total/)).toBeVisible();
80	
81		const coldFirstPaint = await readFirstPaint(page);
82	
83		await page.reload({ waitUntil: 'domcontentloaded', timeout: 60_000 });
84		await expect(page.getByRole('heading', { name: 'Artifacts' })).toBeVisible({ timeout: 60_000 });
85		await expect(page.getByText(/2000 total/)).toBeVisible();
86		const warmFirstPaint = await readFirstPaint(page);
87	
88		const scroll = await measureScrollSmoothness(page);
89	
90		const search = page.getByPlaceholder('Search title or path…');
91		const searchStart = performance.now();
92		await search.fill('Scale Artifact 1999');
93		await expect(page.getByText(/1 total/)).toBeVisible();
94		const searchLatencyMs = Math.round(performance.now() - searchStart);
95	
96		expect(coldFirstPaint).toBeGreaterThan(0);
97		expect(warmFirstPaint).toBeGreaterThan(0);
98		expect(scroll.samples).toBeGreaterThan(0);
99		expect(searchLatencyMs).toBeGreaterThan(0);
100	});
