108	async function installRunRoutes(
109		page: import('@playwright/test').Page,
110		options: {
111			bundleFiles: BundleFileFixture[];
112			bundleContent: Record<string, RunBundleFileContentFixture>;
113			evidenceRequests: string[];
114		}
115	) {
116		await page.route('/graphql', async (route) => {
117			const body = route.request().postDataJSON() as {
118				query: string;
119				variables?: Record<string, unknown>;
120			};
121			if (body.query.includes('NodeInfo')) {
122				await route.fulfill({
123					status: 200,
124					contentType: 'application/json',
125					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
126				});
127				return;
128			}
129			if (body.query.includes('ProjectsForLayout') || body.query.includes('Projects')) {
130				await route.fulfill({
131					status: 200,
132					contentType: 'application/json',
133					body: JSON.stringify({ data: { projects: { edges: PROJECTS.map((node) => ({ node })) } } })
134				});
135				return;
136			}
137			if (body.query.includes('RunHeader') || body.query.includes('RunDetailExpand')) {
138				await route.fulfill({
139					status: 200,
140					contentType: 'application/json',
141					body: JSON.stringify({ data: { run: runDetailResponse() } })
142				});
143				return;
144			}
145			if (body.query.includes('RunEvidenceFiles')) {
146				options.evidenceRequests.push(String(body.variables?.['id'] ?? ''));
147				await route.fulfill({
148					status: 200,
149					contentType: 'application/json',
150					body: JSON.stringify({
151						data: {
152							run: {
153								id: RUN_ID,
154								bundleFiles: options.bundleFiles
155							}
156						}
157					})
158				});
159				return;
160			}
161			if (body.query.includes('RunSessionExpand')) {
162				await route.fulfill({
163					status: 200,
164					contentType: 'application/json',
165					body: JSON.stringify({ data: { agentSession: null } })
166				});
167				return;
168			}
169			if (body.query.includes('RunToolCallsExpand')) {
170				await route.fulfill({
171					status: 200,
172					contentType: 'application/json',
173					body: JSON.stringify({
174						data: {
175							runToolCalls: {
176								edges: [],
177								pageInfo: { hasNextPage: false, endCursor: null },
178								totalCount: 0
179							}
180						}
181					})
182				});
183				return;
184			}
185			if (body.query.includes('RunBundleFileFetch')) {
186				const path = String(body.variables?.['path'] ?? '');
187				const payload = options.bundleContent[path];
188				await route.fulfill({
189					status: 200,
190					contentType: 'application/json',
191					body: JSON.stringify({ data: { runBundleFile: payload ?? null } })
192				});
193				return;
194			}
195			if (body.query.includes('ProducedArtifact')) {
196				await route.fulfill({
197					status: 200,
198					contentType: 'application/json',
199					body: JSON.stringify({ data: { artifact: null } })
200				});
201				return;
202			}
203			await route.continue();
204		});
205	}
