16	
17		type Tab = 'overview' | 'prompt' | 'response' | 'tools' | 'session' | 'evidence';
18	
19		interface Props {
20			runId: string;
21			layer: string;
22			nodeId: string;
23			projectId: string;
24			initialTab?: Tab;
25			onTabChange?: (tab: Tab) => void;
26		}
27	
28		let { runId, layer, nodeId, projectId, initialTab = 'overview', onTabChange }: Props = $props();
29	
30		let run = $state<RunDetail | null>(null);
31		let runLoading = $state(false);
32	
33		let session = $state<SessionDetail | null>(null);
34		let sessionLoading = $state(false);
35		let sessionLoaded = $state(false);
36	
37		let evidenceFiles = $state<BundleFile[]>([]);
38		let evidenceLoading = $state(false);
39		let evidenceLoaded = $state(false);
40	
41		let toolCalls = $state<ToolCall[]>([]);
