43		let toolCallsCursor = $state<string | null>(null);
44		let toolCallsHasMore = $state(false);
45		let toolCallsLoading = $state(false);
46		let toolCallsLoaded = $state(false);
47	
48		let activeTab = $state<Tab>(initialTab);
49		let lastInitialTab = $state<Tab>(initialTab);
50	
51		$effect(() => {
52			if (initialTab !== lastInitialTab) {
53				activeTab = initialTab;
54				lastInitialTab = initialTab;
55				if (activeTab === 'tools' && !toolCallsLoaded) {
56					void fetchToolCalls(false);
57				}
58			}
59		});
60	
61		function beadHref(beadId: string): string {
62			return `/nodes/${nodeId}/projects/${projectId}/beads/${beadId}`;
63		}
64	
65		function workerHref(workerId: string): string {
66			return `/nodes/${nodeId}/projects/${projectId}/workers/${workerId}`;
67		}
68	
69		async function fetchRun() {
70			if (run || runLoading) return;
71			runLoading = true;
72			try {
73				const client = createClient();
74				const data = await client.request<{ run: RunDetail | null }>(RUN_DETAIL_QUERY, { id: runId });
75				run = data.run;
76			} finally {
77				runLoading = false;
78			}
79		}
80	
81		async function fetchEvidence() {
82			if (evidenceLoaded || evidenceLoading) return;
83			evidenceLoading = true;
84			try {
85				const client = createClient();
86				const data = await client.request<{
87					run: { id: string; bundleFiles: BundleFile[] } | null;
88				}>(RUN_EVIDENCE_QUERY, { id: runId });
89				evidenceFiles = data.run?.bundleFiles ?? [];
90			} finally {
91				evidenceLoading = false;
92				evidenceLoaded = true;
93			}
94		}
95	
96		async function fetchSession(sessionId: string) {
97			if (sessionLoaded || sessionLoading) return;
98			sessionLoading = true;
99			try {
100				const client = createClient();
101				const data = await client.request<{ agentSession: SessionDetail | null }>(RUN_SESSION_QUERY, {
102					id: sessionId
103				});
104				session = data.agentSession;
105				sessionLoaded = true;
106			} catch {
107				sessionLoaded = true;
108			} finally {
109				sessionLoading = false;
110			}
111		}
112	
113		async function fetchToolCalls(more = false) {
114			if (toolCallsLoading) return;
115			toolCallsLoading = true;
116			try {
117				const client = createClient();
118				const data = await client.request<{
119					runToolCalls: {
120						edges: Array<{ node: ToolCall; cursor: string }>;
121						pageInfo: { hasNextPage: boolean; endCursor: string | null };
122						totalCount: number;
123					};
124				}>(RUN_TOOL_CALLS_QUERY, {
125					id: runId,
126					first: 50,
127					after: more ? toolCallsCursor : null
128				});
129				const newCalls = data.runToolCalls.edges.map((e) => e.node);
130				toolCalls = more ? [...toolCalls, ...newCalls] : newCalls;
131				toolCallsTotal = data.runToolCalls.totalCount;
132				toolCallsCursor = data.runToolCalls.pageInfo.endCursor;
133				toolCallsHasMore = data.runToolCalls.pageInfo.hasNextPage;
134				toolCallsLoaded = true;
135			} catch {
136				toolCallsLoaded = true;
137			} finally {
138				toolCallsLoading = false;
139			}
140		}
141	
142		$effect(() => {
143			void fetchRun();
144			if (layer === 'run') {
145				void fetchSession(runId);
146			}
147			if (activeTab === 'tools' && !toolCallsLoaded && !toolCallsLoading) {
148				void fetchToolCalls(false);
149			}
150			if (activeTab === 'evidence' && !evidenceLoaded && !evidenceLoading) {
151				void fetchEvidence();
152			}
153		});
154	
155		function pickTab(tab: Tab) {
156			activeTab = tab;
157			if (tab === 'tools' && !toolCallsLoaded) {
158				void fetchToolCalls(false);
159			}
160			if (tab === 'evidence' && !evidenceLoaded) {
161				void fetchEvidence();
162			}
163			onTabChange?.(tab);
164		}
165	
166		const tabs: Array<{ id: Tab; label: string }> = $derived.by(() => {
167			const list: Array<{ id: Tab; label: string }> = [{ id: 'overview', label: 'Overview' }];
168			if (layer !== 'work') {
169				list.push({ id: 'prompt', label: 'Prompt' });
170				list.push({ id: 'response', label: 'Response' });
171			}
172			if (layer === 'run') {
173				list.push({ id: 'session', label: 'Session' });
174			}
175			if (layer === 'run' || layer === 'try') {
176				list.push({ id: 'tools', label: 'Tools' });
177				list.push({ id: 'evidence', label: 'Evidence' });
178			}
179			return list;
180		});
181	</script>
