29					Loading…
30				{:else}
31					{calls.length}{total != null ? ` of ${total}` : ''} tool calls
32				{/if}
33			</span>
34			{#if sourcePath}
35				<span>Source: <code class="font-mono-code text-mono-code">{sourcePath}</code></span>
36			{/if}
37		</div>
38		{#if !loading && calls.length === 0}
39			<div class="border border-border-line bg-bg-surface p-3 text-body-sm text-fg-muted dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-muted">
40				No tool calls were captured.
41			</div>
42		{/if}
43		<ul class="space-y-1">
44			{#each calls as call (call.seq)}
45				{@const open = expanded.has(call.seq)}
46				<li class="border border-border-line dark:border-dark-border-line">
47					<button
48						type="button"
49						data-tool-seq={call.seq}
50						class="flex w-full items-center justify-between px-3 py-2 text-left hover:bg-bg-surface dark:hover:bg-dark-bg-surface"
51						onclick={(e) => {
52							e.stopPropagation()
53							toggleCall(call.seq)
54						}}
55					>
56						<span class="flex items-center gap-2">
57							<span class="font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">#{call.seq}</span>
58							<span class="text-body-sm font-medium text-fg-ink dark:text-dark-fg-ink">{call.name}</span>
59						</span>
60						<span class="text-label-caps font-label-caps text-fg-muted dark:text-dark-fg-muted">{open ? '▾' : '▸'}</span>
61					</button>
62					{#if open}
63						<div class="space-y-2 border-t border-border-line px-3 py-2 dark:border-dark-border-line">
64							<div class="flex flex-wrap items-center gap-3 text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">
65								<span>Tool: <span class="text-fg-ink dark:text-dark-fg-ink">{call.name}</span></span>
66								{#if call.durationMs != null}
67									<span>Duration: <span class="text-fg-ink dark:text-dark-fg-ink">{call.durationMs}ms</span></span>
68								{/if}
69							</div>
70							{#if call.inputs}
71								<div>
72									<div class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Inputs</div>
73									<pre class="mt-1 max-h-56 overflow-auto bg-terminal-bg px-3 py-2 font-mono-code text-mono-code text-terminal-fg whitespace-pre-wrap">{tryPretty(call.inputs)}</pre>
74								</div>
75							{/if}
76							{#if call.output}
77								<div>
78									<div class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Output</div>
79									<pre class="mt-1 max-h-56 overflow-auto bg-terminal-bg px-3 py-2 font-mono-code text-mono-code text-terminal-fg whitespace-pre-wrap">{call.output}</pre>
80								</div>
81							{/if}
82							{#if call.error}
83								<div>
84									<div class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Error</div>
85									<pre class="mt-1 max-h-56 overflow-auto bg-terminal-bg px-3 py-2 font-mono-code text-mono-code text-terminal-fg whitespace-pre-wrap">{call.error}</pre>
86								</div>
87							{/if}
88						</div>
89					{/if}
90				</li>
91			{/each}
92		</ul>
93		{#if hasMore && onLoadMore}
94			<div class="pt-2">
95				<button
96					type="button"
97					onclick={(e) => {
98						e.stopPropagation()
99						onLoadMore?.()
100					}}
101					disabled={loading}
102					class="border border-border-line px-3 py-1.5 text-body-sm text-fg-muted hover:bg-bg-surface disabled:opacity-50 dark:border-dark-border-line dark:text-dark-fg-muted dark:hover:bg-dark-bg-surface"
103				>
104					{loading ? 'Loading…' : 'Load more'}
105				</button>
106			</div>
107		{/if}
108	</div>
